// Affiche une notification locale de façon compatible Android + ordinateur + PWA.
// IMPORTANT : Android (Chrome) interdit `new Notification(...)` (« Illegal constructor »).
// Il faut passer par le service worker : registration.showNotification(...).
// On garde `new Notification` en repli pour les navigateurs desktop sans service worker actif.
function showMoyoNotification(title: string, body: string) {
  try {
    if (typeof window === "undefined" || !("Notification" in window)) return;
    if (Notification.permission !== "granted") return;
    const options: NotificationOptions = { body, icon: "/favicon.png", badge: "/favicon.png" };
    if ("serviceWorker" in navigator && navigator.serviceWorker) {
      navigator.serviceWorker.ready
        .then(reg => reg.showNotification(title, options))
        .catch(() => { try { new Notification(title, options); } catch {} });
    } else {
      try { new Notification(title, options); } catch {}
    }
  } catch {}
}

// Clé publique VAPID — sans danger à exposer côté client (la clé privée reste dans Supabase).
const VAPID_PUBLIC_KEY = "BLpwfiAkbki0qgQyg1ioTaCfUwCyQyDEBxWOuTe1fbXb1EwWnvIpSwpuLu9KqiRe9d61XIwaDi-H8hNsDVdfF7U";

// Convertit la clé VAPID (base64url) au format binaire attendu par pushManager.subscribe.
function urlBase64ToUint8Array(base64String: string): Uint8Array {
  const padding = "=".repeat((4 - (base64String.length % 4)) % 4);
  const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
  const raw = atob(base64);
  const arr = new Uint8Array(raw.length);
  for (let i = 0; i < raw.length; i++) arr[i] = raw.charCodeAt(i);
  return arr;
}

// Abonne l'appareil au push et enregistre sa "boîte aux lettres" dans Supabase.
// Invisible pour l'utilisateur : il a juste cliqué "Autoriser". Sans danger si déjà abonné.
async function subscribeToPush(auth: { token: string; userId: string }) {
  try {
    if (typeof window === "undefined") return;
    if (!("serviceWorker" in navigator) || !("PushManager" in window)) return;
    if (!("Notification" in window) || Notification.permission !== "granted") return;
    const reg = await navigator.serviceWorker.ready;
    let sub = await reg.pushManager.getSubscription();
    if (!sub) {
      sub = await reg.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY) as unknown as BufferSource,
      });
    }
    const json = sub.toJSON() as { endpoint?: string; keys?: { p256dh?: string; auth?: string } };
    await fetch(`${SUPABASE_URL}/rest/v1/push_subscriptions?on_conflict=endpoint`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "apikey": SUPABASE_KEY,
        "Authorization": `Bearer ${auth.token}`,
        "Prefer": "resolution=merge-duplicates,return=minimal",
      },
      body: JSON.stringify({
        user_id: auth.userId,
        endpoint: json.endpoint,
        p256dh: json.keys?.p256dh,
        auth_key: json.keys?.auth,
      }),
    });
  } catch {}
}

// Demande l'autorisation puis abonne. Renvoie un statut pour informer l'utilisateur.
// "granted" = activé, "denied" = refusé (bloqué par le navigateur), "unsupported" = non géré.
async function enableNotifications(auth: { token: string; userId: string }): Promise<"granted" | "denied" | "unsupported"> {
  try {
    if (typeof window === "undefined") return "unsupported";
    if (!("Notification" in window) || !("serviceWorker" in navigator) || !("PushManager" in window)) return "unsupported";
    let perm = Notification.permission;
    if (perm === "default") {
      perm = await Notification.requestPermission();
    }
    if (perm !== "granted") return "denied";
    await subscribeToPush(auth);
    return "granted";
  } catch {
    return "unsupported";
  }
}

export type Auth = {
  token: string;
  userId: string;
  name: string;
  email: string;
  isPremium: boolean;
  isAdmin: boolean;
  adminLevel?: "admin" | "superadmin";
  refreshToken?: string;
  expiresAt?: number;
};
export type Profile = { id: string; name: string; age: number; city: string; gender: string; bio: string; religion?: string; profession?: string; hobbies?: string; phone?: string | null; photo_url?: string | null; is_premium: boolean; is_admin?: boolean; is_visible?: boolean; is_verified?: boolean; is_certified?: boolean; last_seen?: string; hide_online_status?: boolean; warning_count?: number; is_banned?: boolean; ban_until?: string | null; ban_reason?: string | null; last_notice_acknowledged?: boolean; last_notice_at?: string | null };
export type Match = { id: string; user1: string; user2: string; partner?: Profile; lastMsg?: Message; unreadCount?: number; created_at?: string };
export type Message = { id?: string; match_id: string; sender_id: string; content: string; is_read: boolean; is_delivered?: boolean; is_edited?: boolean; created_at?: string; reactions?: Record<string, string[]>; is_view_once?: boolean; viewed_at?: string | null; is_destroyed?: boolean; destroyed_at?: string | null };
// Ciblage des diffusions générales : décide si une diffusion (target) concerne un utilisateur donné.
// target peut être composite "genre|abonnement" (ex. "femmes|premium") ou une ancienne valeur simple.
const broadcastTargetsUser = (target: string | null | undefined, isPremium: boolean, gender: string): boolean => {
  const t = (target || "all").toLowerCase();
  if (t.includes("|")) {
    const [g, p] = t.split("|");
    const genderOk = g === "all" || (g === "femmes" && gender === "Femme") || (g === "hommes" && gender === "Homme");
    const planOk = p === "all" || (p === "premium" && isPremium) || (p === "gratuit" && !isPremium);
    return genderOk && planOk;
  }
  switch (t) {
    case "femmes": return gender === "Femme";
    case "hommes": return gender === "Homme";
    case "premium": return !!isPremium;
    case "gratuit": return !isPremium;
    default: return true; // "all"
  }
};
export type StatusPost = { id?: string; user_id: string; image_url?: string | null; image_path?: string | null; caption?: string | null; text?: string | null; created_at?: string; expires_at?: string; profile?: Profile; is_official?: boolean; is_sponsored?: boolean; link_url?: string | null; is_feature?: boolean; target_gender?: string | null; feature_user_id?: string | null; feature_profile?: Profile };
export type ToastState = { msg: string; type?: "success" | "error" | "premium" } | null;

